'use client';

import { useEffect, useRef } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { motion } from 'framer-motion';
import { ArrowUpRight, MapPin } from 'lucide-react';
import type { Cooperative } from '../data/mockData';
import { useCooperativeStore } from '../store/useCooperativeStore';

type CooperativeListProps = {
  cooperatives: Cooperative[];
  className?: string;
  compact?: boolean;
};

export default function CooperativeList({
  cooperatives,
  className,
  compact = false,
}: CooperativeListProps) {
  const activeCooperativeId = useCooperativeStore((state) => state.activeCooperativeId);
  const setActiveCooperativeId = useCooperativeStore((state) => state.setActiveCooperativeId);
  const itemRefs = useRef<Record<string, HTMLDivElement | null>>({});

  useEffect(() => {
    if (!activeCooperativeId) return;

    const target = itemRefs.current[activeCooperativeId];
    if (!target) return;

    target.scrollIntoView({
      behavior: 'smooth',
      block: 'center',
    });
  }, [activeCooperativeId]);

  return (
    <aside
      className={`overflow-y-auto rounded-2xl border border-white/40 bg-white/70 p-3 shadow-lg backdrop-blur-md ${
        compact ? 'h-full' : 'h-[60vh] lg:h-[72vh]'
      } ${className ?? ''}`}
    >
      <div className="space-y-3">
        {cooperatives.map((cooperative, index) => {
          const isActive = cooperative.id === activeCooperativeId;

          return (
            <motion.div
              key={cooperative.id}
              ref={(node) => {
                itemRefs.current[cooperative.id] = node;
              }}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.3, delay: index * 0.04 }}
              onClick={() => setActiveCooperativeId(cooperative.id)}
              className={`cursor-pointer rounded-2xl border p-4 transition ${
                isActive
                  ? 'border-terracotta/70 bg-terracotta/10 shadow-xl'
                  : 'border-white/40 bg-white/50 hover:shadow-lg'
              }`}
            >
              <div className="mb-3 flex items-start justify-between gap-3">
                <div className="flex items-start gap-3">
                  <div className="relative mt-0.5 h-12 w-12 overflow-hidden rounded-xl border border-white/50">
                    <Image
                      src={cooperative.coverImage}
                      alt={cooperative.coverAlt}
                      fill
                      sizes="48px"
                      className="object-cover"
                    />
                  </div>
                  <div>
                    <p className="text-xs uppercase tracking-wide text-terracotta">
                      {cooperative.zone} • {cooperative.category}
                    </p>
                    <h3 className="text-base font-semibold text-palmier">{cooperative.name}</h3>
                  </div>
                </div>
                <MapPin
                  size={18}
                  className={isActive ? 'text-terracotta' : 'text-palmier/60'}
                />
              </div>

              <p className="mb-2 text-sm text-palmier/80">{cooperative.descriptionShort}</p>
              <p className="mb-4 text-xs text-palmier/70">{cooperative.location.address}</p>

              <div className="mb-3 flex flex-wrap gap-1">
                {cooperative.products.slice(0, 2).map((product) => (
                  <span
                    key={product.id}
                    className="rounded-full bg-palmier/10 px-2 py-1 text-[11px] text-palmier/75"
                  >
                    {product.name}
                  </span>
                ))}
              </div>

              <div className="flex items-center justify-between">
                <span className="text-xs font-medium text-palmier/70">
                  {cooperative.products.length} produit
                  {cooperative.products.length > 1 ? 's' : ''}
                </span>
                <Link
                  href={`/cooperative/${cooperative.slug}`}
                  className="inline-flex items-center gap-1 text-sm font-medium text-palmier hover:text-terracotta"
                  onClick={(event) => event.stopPropagation()}
                >
                  Voir profil
                  <ArrowUpRight size={14} />
                </Link>
              </div>
            </motion.div>
          );
        })}
      </div>
    </aside>
  );
}
